export default function getIntlMessage(key: keyof typeof MessageMap) {
    const currentLocale = i18n.intl.currentLocale as DiscordLocale;

    const entry = MessageMap[key];

    if (!entry) {
        console.warn("Message does not exist in the intl message map");
        return;
    }

    return (
        entry[currentLocale] ??
        entry["en-US"] ??
        key
    );
}
